   "source": "<ROUTINE READ-BEG ()\n\t <TELL \"\\\"\">\n\t <COND (<PROB 50>\n\t\t<TELL \"Go ahead, dear. \">)>\n\t <COND (<PROB 50>\n\t\t<TELL \"Don't be bashful. \">)>\n\t <COND (<FSET? ,OPEN-ENVELOPE ,TOUCHBIT>\n\t\t<THIS-IS-IT ,RANSOM-LETTER>\n\t\t<TELL \"R\">)\n\t       (T\n\t\t<THIS-IS-IT ,ENVELOPE>\n\t\t<TELL \"Open the envelope and r\">)>\n\t <TELL \"ead the letter to me\">\n\t <COND (<PROB 50>\n\t\t<TELL \", please\">)>\n\t <COND (<PROB 50>\n\t\t<TELL \". I'm waiting\">)>\n\t <TELL \".\\\"\" CR>>"
